DROP TABLE IF EXISTS "incidents" CASCADE;
CREATE TABLE "incidents" (
  "tenant_id" TEXT,
  "incident_id" TEXT PRIMARY KEY,
  "title" TEXT,
  "description" TEXT,
  "status" TEXT,
  "priority" TEXT,
  "severity" TEXT,
  "impact" TEXT,
  "urgency" TEXT,
  "category" TEXT,
  "subcategory" TEXT,
  "service_name" TEXT,
  "reported_by" TEXT,
  "assigned_to" TEXT,
  "assignment_group" TEXT,
  "ci_id" TEXT,
  "linked_ci_ids" JSONB,
  "related_problem" TEXT,
  "related_change" TEXT,
  "attachments" JSONB,
  "work_notes" JSONB,
