INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001001', 'VPN disconnects on Wi-Fi handoff', 'VPN session drops every time the user moves between SSIDs at HQ. Started two days ago; affects multiple floors. User reports it is now blocking productive work because they have to reconnect every few minutes.', 'open', 'P2', 'high', 'medium', 'high', 'network', 'vpn', 'Corporate VPN', 'USR00009', 'USR00003', 'GRP-NETOPS', 'CI0000001', '["CI0000001", "CI0000007"]'::jsonb, 'PBM0003001', 'CHG0004001', '[{"attachment_id": "ATT-INC0001001-01", "name": "vpn_drop_screenshot.png", "mime_type": "image/png", "size_bytes": 184320, "uploaded_at": "2026-04-01T09:14:00Z"}]'::jsonb, '[{"note_id": "WN-INC0001001-01", "author": "USR00003", "author_role": "agent", "is_public": false, "timestamp": "2026-04-01T09:35:00Z", "text": "Reviewed firewall logs. IKE keepalive failing on AP roaming events. Pattern matches PBM0003001."}, {"note_id": "WN-INC0001001-02", "author": "USR00003", "author_role": "agent", "is_public": false, "timestamp": "2026-04-01T11:20:00Z", "text": "Tried bumping client keepalive to 30s \u2014 no improvement. Next: try gateway-side keepalive."}, {"note_id": "WN-INC0001001-03", "author": "USR00003", "author_role": "agent", "is_public": false, "timestamp": "2026-04-01T14:50:00Z", "text": "Confirmed root cause is keepalive mismatch between client v2.2 and gateway profile. Fix is rolling out via CHG0004001 tonight."}]'::jsonb, '[{"comment_id": "COM-INC0001001-01", "author": "USR00009", "author_role": "customer", "is_public": true, "timestamp": "2026-04-01T09:10:00Z", "text": "I''m trying to work from the cafeteria and the VPN drops every time I walk past the elevators. This is the third day in a row. I have a deadline today."}, {"comment_id": "COM-INC0001001-02", "author": "USR00003", "author_role": "agent", "is_public": true, "timestamp": "2026-04-01T09:45:00Z", "text": "Thanks for reporting. We''ve identified this as part of a known VPN roaming issue. A fix is rolling out tonight via change CHG0004001. As an immediate workaround, please stay on a single AP if possible."}, {"comment_id": "COM-INC0001001-03", "author": "USR00009", "author_role": "customer", "is_public": true, "timestamp": "2026-04-01T13:30:00Z", "text": "Workaround helps a bit but still drops every 15 minutes. Any ETA?"}, {"comment_id": "COM-INC0001001-04", "author": "USR00003", "author_role": "agent", "is_public": true, "timestamp": "2026-04-01T15:00:00Z", "text": "Patch deployment scheduled for 22:00 tonight. You should see stable connections from tomorrow morning. Sorry for the disruption."}]'::jsonb, '2026-04-01T17:10:00Z'::timestamptz, FALSE, '2026-04-01T09:10:00Z'::timestamptz, '2026-04-01T15:00:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001002', 'VPN drops after 10 minutes', 'Session disconnects repeatedly after login. User has to reconnect every 10 minutes which interrupts video calls.', 'in_progress', 'P2', 'high', 'medium', 'high', 'network', 'vpn', 'Corporate VPN', 'USR00010', 'USR00003', 'GRP-NETOPS', 'CI0000001', '["CI0000001"]'::jsonb, 'PBM0003001', NULL, '[]'::jsonb, '[{"note_id": "WN-INC0001002-01", "author": "USR00003", "author_role": "agent", "is_public": false, "timestamp": "2026-04-01T10:15:00Z", "text": "Same symptom as INC0001001. Linking to PBM0003001."}]'::jsonb, '[{"comment_id": "COM-INC0001002-01", "author": "USR00010", "author_role": "customer", "is_public": true, "timestamp": "2026-04-01T10:00:00Z", "text": "VPN drops every 10 minutes. I''m in back-to-back client calls and this is embarrassing."}, {"comment_id": "COM-INC0001002-02", "author": "USR00003", "author_role": "agent", "is_public": true, "timestamp": "2026-04-01T10:30:00Z", "text": "We are aware of this issue. A fix is being deployed tonight. Apologies for the inconvenience."}]'::jsonb, '2026-04-01T18:00:00Z'::timestamptz, FALSE, '2026-04-01T10:00:00Z'::timestamptz, '2026-04-01T10:30:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001003', 'Unable to connect to VPN from home', 'Client shows tunnel negotiation timeout. User cannot reach internal resources.', 'resolved', 'P2', 'high', 'medium', 'high', 'network', 'vpn', 'Corporate VPN', 'USR00018', 'USR00003', 'GRP-NETOPS', 'CI0000002', '["CI0000002"]'::jsonb, NULL, NULL, '[]'::jsonb, '[{"note_id": "WN-INC0001003-01", "author": "USR00003", "author_role": "agent", "is_public": false, "timestamp": "2026-04-01T13:00:00Z", "text": "Local firewall on user''s home router was blocking UDP 4500. User reconfigured router and connection restored."}]'::jsonb, '[{"comment_id": "COM-INC0001003-01", "author": "USR00018", "author_role": "customer", "is_public": true, "timestamp": "2026-04-01T12:45:00Z", "text": "I keep getting tunnel negotiation timeout from home."}, {"comment_id": "COM-INC0001003-02", "author": "USR00003", "author_role": "agent", "is_public": true, "timestamp": "2026-04-01T13:15:00Z", "text": "Please check that your home router allows UDP traffic on ports 500 and 4500. If you have a recent NAT firmware update, that often blocks IPSec NAT-T."}, {"comment_id": "COM-INC0001003-03", "author": "USR00018", "author_role": "customer", "is_public": true, "timestamp": "2026-04-01T13:55:00Z", "text": "That fixed it. Thank you so much, I was about to give up and drive into the office!"}]'::jsonb, '2026-04-01T20:45:00Z'::timestamptz, FALSE, '2026-04-01T12:45:00Z'::timestamptz, '2026-04-01T14:00:00Z'::timestamptz, '2026-04-01T14:00:00Z'::timestamptz, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001004', 'Outlook not syncing new emails', 'Inbox updates delayed by over 20 minutes for a finance user. Emails arrive but with significant lag.', 'open', 'P3', 'medium', 'low', 'medium', 'email', 'outlook', 'Microsoft Exchange', 'USR00007', 'USR00014', 'GRP-APPS', 'CI0000003', '["CI0000003"]'::jsonb, 'PBM0003002', NULL, '[]'::jsonb, '[]'::jsonb, '[{"comment_id": "COM-INC0001004-01", "author": "USR00007", "author_role": "customer", "is_public": true, "timestamp": "2026-04-02T08:05:00Z", "text": "My Outlook is showing emails from 25 minutes ago as new. Is something wrong with the mail server?"}]'::jsonb, '2026-04-03T08:05:00Z'::timestamptz, FALSE, '2026-04-02T08:05:00Z'::timestamptz, '2026-04-02T08:05:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001005', 'Mailbox access denied intermittently', 'User can open mailbox only after multiple retries. Pattern is intermittent and affects only some users.', 'in_progress', 'P3', 'medium', 'medium', 'medium', 'email', 'exchange', 'Microsoft Exchange', 'USR00008', 'USR00014', 'GRP-APPS', 'CI0000003', '["CI0000003"]'::jsonb, 'PBM0003002', NULL, '[]'::jsonb, '[{"note_id": "WN-INC0001005-01", "author": "USR00014", "author_role": "agent", "is_public": false, "timestamp": "2026-04-02T10:00:00Z", "text": "Restarted transport service on passive node. Watching queue depth."}]'::jsonb, '[]'::jsonb, '2026-04-03T09:30:00Z'::timestamptz, FALSE, '2026-04-02T09:30:00Z'::timestamptz, '2026-04-02T10:00:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001006', 'HR portal login fails with 500', 'Portal throws internal server error after SSO redirect. Affects an HR director who needs to approve payroll changes today.', 'open', 'P2', 'high', 'high', 'high', 'application', 'portal', 'HR Portal', 'USR00008', 'USR00013', 'GRP-APPS', 'CI0000004', '["CI0000004", "CI0000008"]'::jsonb, NULL, NULL, '[{"attachment_id": "ATT-INC0001006-01", "name": "hr_portal_500_error.png", "mime_type": "image/png", "size_bytes": 92160, "uploaded_at": "2026-04-02T10:42:00Z"}]'::jsonb, '[{"note_id": "WN-INC0001006-01", "author": "USR00013", "author_role": "agent", "is_public": false, "timestamp": "2026-04-02T11:00:00Z", "text": "VIP user. Captured correlation ID 8f2a4c. Backend trace shows SAML assertion rejected by HR Portal."}, {"note_id": "WN-INC0001006-02", "author": "USR00013", "author_role": "agent", "is_public": false, "timestamp": "2026-04-02T11:15:00Z", "text": "Cross-checking with INC0001030 \u2014 same SAML assertion error pattern. Possibly related to identity provider replication lag."}]'::jsonb, '[{"comment_id": "COM-INC0001006-01", "author": "USR00008", "author_role": "customer", "is_public": true, "timestamp": "2026-04-02T10:40:00Z", "text": "I cannot get into the HR portal. I have payroll approvals that have to go through today by 5pm. Please make this a priority."}, {"comment_id": "COM-INC0001006-02", "author": "USR00013", "author_role": "agent", "is_public": true, "timestamp": "2026-04-02T11:10:00Z", "text": "We''re treating this as urgent. We have a correlation ID and are investigating the SSO assertion path. Will update within 30 minutes."}]'::jsonb, '2026-04-02T18:40:00Z'::timestamptz, FALSE, '2026-04-02T10:40:00Z'::timestamptz, '2026-04-02T11:15:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001007', 'Payroll report generation timeout', 'Monthly payroll report fails after 5 minutes. Finance team cannot close month-end accounts.', 'in_progress', 'P1', 'critical', 'high', 'high', 'database', 'performance', 'Payroll Database', 'USR00007', 'USR00004', 'GRP-DBA', 'CI0000005', '["CI0000005"]'::jsonb, 'PBM0003003', NULL, '[]'::jsonb, '[{"note_id": "WN-INC0001007-01", "author": "USR00004", "author_role": "agent", "is_public": false, "timestamp": "2026-04-02T11:30:00Z", "text": "Confirmed timeout. Lock contention between report job and posting job. Same root cause as PBM0003003. Workaround: run report in read-only replica window."}, {"note_id": "WN-INC0001007-02", "author": "USR00004", "author_role": "agent", "is_public": false, "timestamp": "2026-04-02T12:00:00Z", "text": "Switched report execution to read-only replica. Job completed in 90 seconds. Permanent fix is composite index via CHG0004003."}]'::jsonb, '[{"comment_id": "COM-INC0001007-01", "author": "USR00007", "author_role": "customer", "is_public": true, "timestamp": "2026-04-02T11:25:00Z", "text": "Payroll report has failed twice this morning. We need this for month-end close today."}, {"comment_id": "COM-INC0001007-02", "author": "USR00004", "author_role": "agent", "is_public": true, "timestamp": "2026-04-02T12:05:00Z", "text": "Report rerun completed using a different execution path. Output should be in your shared folder. A permanent fix is scheduled for this week."}]'::jsonb, '2026-04-02T15:25:00Z'::timestamptz, FALSE, '2026-04-02T11:25:00Z'::timestamptz, '2026-04-02T12:05:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001008', 'Salesforce sync lagging', 'Lead updates not syncing to ERP for 30 minutes.', 'open', 'P3', 'medium', 'medium', 'medium', 'integration', 'sync', 'Salesforce Integration', 'USR00009', 'USR00012', 'GRP-PLATFORM', 'CI0000006', '["CI0000006"]'::jsonb, NULL, NULL, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '2026-04-03T12:10:00Z'::timestamptz, FALSE, '2026-04-02T12:10:00Z'::timestamptz, '2026-04-02T12:10:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001009', 'Office Wi-Fi unstable floor 5', 'Frequent disconnects and packet loss on floor 5. Affects roughly 20 users on the engineering floor.', 'resolved', 'P2', 'high', 'high', 'medium', 'network', 'wifi', 'Corporate Wi-Fi', 'USR00018', 'USR00003', 'GRP-NETOPS', 'CI0000007', '["CI0000007"]'::jsonb, 'PBM0003004', NULL, '[]'::jsonb, '[{"note_id": "WN-INC0001009-01", "author": "USR00003", "author_role": "agent", "is_public": false, "timestamp": "2026-04-03T08:30:00Z", "text": "RF scan shows channel overlap on floor 5 APs. Auto-channel policy is fighting itself."}, {"note_id": "WN-INC0001009-02", "author": "USR00003", "author_role": "agent", "is_public": false, "timestamp": "2026-04-03T11:00:00Z", "text": "Pinned channels 36/44/149 for floor 5. Stability returned. Linked emergency change CHG0004004."}]'::jsonb, '[{"comment_id": "COM-INC0001009-01", "author": "USR00018", "author_role": "customer", "is_public": true, "timestamp": "2026-04-03T07:40:00Z", "text": "Wi-Fi on floor 5 is dropping for everyone. Half the team is on hotspots."}, {"comment_id": "COM-INC0001009-02", "author": "USR00003", "author_role": "agent", "is_public": true, "timestamp": "2026-04-03T11:30:00Z", "text": "Resolved. We pinned the channels for floor 5 APs to stop the auto-channel conflict. You should see stable Wi-Fi now. Sorry for the disruption."}]'::jsonb, '2026-04-03T15:40:00Z'::timestamptz, FALSE, '2026-04-03T07:40:00Z'::timestamptz, '2026-04-03T11:30:00Z'::timestamptz, '2026-04-03T11:30:00Z'::timestamptz, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001010', 'MFA prompt loop after password reset', 'SSO asks for MFA repeatedly without success after a password reset.', 'open', 'P2', 'high', 'medium', 'high', 'security', 'mfa', 'SSO Identity Provider', 'USR00019', 'USR00011', 'GRP-SECOPS', 'CI0000008', '["CI0000008"]'::jsonb, 'PBM0003005', NULL, '[]'::jsonb, '[]'::jsonb, '[{"comment_id": "COM-INC0001010-01", "author": "USR00019", "author_role": "customer", "is_public": true, "timestamp": "2026-04-03T08:55:00Z", "text": "I reset my password this morning and now I''m stuck in an MFA loop. I cannot log in to anything. I have a board meeting in 90 minutes."}]'::jsonb, '2026-04-03T16:55:00Z'::timestamptz, FALSE, '2026-04-03T08:55:00Z'::timestamptz, '2026-04-03T08:55:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001011', 'Service desk portal slow', 'Ticket list takes 25 seconds to load. Service desk agents cannot work efficiently.', 'in_progress', 'P3', 'medium', 'medium', 'medium', 'application', 'itsm_portal', 'Service Desk Portal', 'USR00002', 'USR00013', 'GRP-APPS', 'CI0000009', '["CI0000009"]'::jsonb, 'PBM0003006', NULL, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '2026-04-04T09:20:00Z'::timestamptz, FALSE, '2026-04-03T09:20:00Z'::timestamptz, '2026-04-03T09:20:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001012', 'Monitoring alerts delayed', 'Alert ingestion delayed by 15 minutes. Network team is not seeing alerts in real time.', 'open', 'P2', 'high', 'high', 'medium', 'platform', 'monitoring', 'Monitoring Stack', 'USR00020', 'USR00012', 'GRP-PLATFORM', 'CI0000010', '["CI0000010"]'::jsonb, 'PBM0003009', NULL, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '2026-04-03T18:05:00Z'::timestamptz, FALSE, '2026-04-03T10:05:00Z'::timestamptz, '2026-04-03T10:05:00Z'::timestamptz, NULL, NULL);
