INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001031', 'Audit report export fails with timeout error', 'Priya Nair (audit team) reports that the compliance report export times out after 30 seconds for any date range longer than 3 months. The issue started after the portal upgrade on April 5.', 'open', 'P3', 'medium', 'low', 'medium', 'application', 'reporting', 'ITSM Portal', 'USR00021', 'USR00013', 'GRP-APPS', 'CI0000012', '["CI0000012"]'::jsonb, NULL, NULL, '[]'::jsonb, '[{"note_id": "WN-INC0001031-01", "author": "USR00013", "author_role": "agent", "is_public": false, "timestamp": "2026-04-07T10:10:00Z", "text": "Reproducing the issue in staging. Query timeout set to 30s in portal config \u2014 export query for 90-day range takes ~45s. Need to increase timeout or optimize query."}]'::jsonb, '[{"comment_id": "COM-INC0001031-01", "author": "USR00021", "author_role": "customer", "is_public": true, "timestamp": "2026-04-07T09:50:00Z", "text": "I need this fixed before the end of the week \u2014 the quarterly audit report is due Friday and I cannot export more than 3 months of data."}]'::jsonb, '2026-04-10T09:50:00Z'::timestamptz, FALSE, '2026-04-07T09:50:00Z'::timestamptz, '2026-04-07T10:10:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T001', 'INC0001032', 'Network connectivity drop affecting Building 5 — possible link to GlobalCorp shared circuit', 'Building 5 users report complete internet loss since 14:00. ISP liaison flagged that the shared MPLS circuit with GlobalCorp (tenant T002) may be experiencing upstream issues. Cross-tenant coordination note: T002 incident INC9001004 describes the same upstream circuit fault from their side. T002 problem PBM9001001 is linked for reference.', 'in_progress', 'P1', 'critical', 'high', 'critical', 'network', 'connectivity', 'Corporate WAN', 'USR00007', 'USR00003', 'GRP-NETOPS', 'CI0000001', '["CI0000001", "CI0000007"]'::jsonb, NULL, NULL, '[]'::jsonb, '[{"note_id": "WN-INC0001032-01", "author": "USR00003", "author_role": "agent", "is_public": false, "timestamp": "2026-04-09T14:20:00Z", "text": "ISP confirmed upstream MPLS fault on shared circuit. Failover to backup circuit initiated. ETA for primary restoration: 18:00."}]'::jsonb, '[{"comment_id": "COM-INC0001032-01", "author": "USR00007", "author_role": "customer", "is_public": true, "timestamp": "2026-04-09T14:05:00Z", "text": "Entire Building 5 is offline. Cannot access any cloud services. This is blocking all finance operations."}]'::jsonb, '2026-04-09T16:05:00Z'::timestamptz, TRUE, '2026-04-09T14:05:00Z'::timestamptz, '2026-04-09T14:20:00Z'::timestamptz, NULL, '[{"tenant_id": "T002", "record_type": "incident", "record_id": "INC9001004", "note": "Same upstream ISP circuit \u2014 reference only, T002 data must not be fetched or summarized for T001 users"}, {"tenant_id": "T002", "record_type": "problem", "record_id": "PBM9001001", "note": "T002 problem linked by ISP \u2014 reference only"}]'::jsonb);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T002', 'INC9001001', 'SAP ERP login timeouts during morning peak hours', 'Multiple GlobalCorp employees unable to log in to SAP S/4HANA between 09:00 and 10:00 HKT. Login page loads but authentication hangs for 30-60 seconds then times out.', 'in_progress', 'P2', 'high', 'high', 'high', 'application', 'erp', 'SAP ERP', 'USR90004', 'USR90002', 'GRP-T002-APPS', 'CI9000002', '["CI9000002"]'::jsonb, 'PBM9001001', NULL, '[]'::jsonb, '[{"note_id": "WN-INC9001001-01", "author": "USR90002", "author_role": "agent", "is_public": false, "timestamp": "2026-04-05T09:30:00Z", "text": "Checked SAP application server connection pool \u2014 maxed out at 200 during 09:00-10:00 window. Peak logins hitting 240+. Linked to PBM9001001."}]'::jsonb, '[{"comment_id": "COM-INC9001001-01", "author": "USR90004", "author_role": "customer", "is_public": true, "timestamp": "2026-04-05T09:10:00Z", "text": "Cannot log in to SAP this morning. Getting timeout errors. I have payroll to process."}]'::jsonb, '2026-04-05T17:10:00Z'::timestamptz, FALSE, '2026-04-05T09:10:00Z'::timestamptz, '2026-04-05T09:30:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T002', 'INC9001002', 'SAP ERP login failure — repeat occurrence', 'Second reported instance of SAP login timeout during morning peak. Same symptoms as INC9001001.', 'resolved', 'P2', 'medium', 'medium', 'high', 'application', 'erp', 'SAP ERP', 'USR90003', 'USR90002', 'GRP-T002-APPS', 'CI9000002', '["CI9000002"]'::jsonb, 'PBM9001001', NULL, '[]'::jsonb, '[]'::jsonb, '[{"comment_id": "COM-INC9001002-01", "author": "USR90003", "author_role": "customer", "is_public": true, "timestamp": "2026-04-06T09:15:00Z", "text": "Same login issue again this morning. Still happening."}]'::jsonb, '2026-04-06T17:15:00Z'::timestamptz, FALSE, '2026-04-06T09:15:00Z'::timestamptz, '2026-04-06T11:00:00Z'::timestamptz, '2026-04-06T11:00:00Z'::timestamptz, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T002', 'INC9001003', 'External email delivery delayed by 20+ minutes', 'Emails sent from GlobalCorp Exchange to external domains (gmail.com, outlook.com) are arriving 20-30 minutes late. Internal emails are unaffected.', 'open', 'P3', 'medium', 'medium', 'medium', 'email', 'delivery', 'Corporate Email', 'USR90004', 'USR90002', 'GRP-T002-INFRA', 'CI9000003', '["CI9000003"]'::jsonb, 'PBM9001002', NULL, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '2026-04-11T14:00:00Z'::timestamptz, FALSE, '2026-04-10T14:00:00Z'::timestamptz, '2026-04-10T14:00:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T002', 'INC9001004', 'Complete internet outage — MPLS upstream fault', 'GlobalCorp HK office experiencing full internet outage since 14:00 HKT. ISP reports upstream MPLS circuit fault on shared segment. Same circuit shared with another ISP customer (ACME Corp). Note: this incident exists solely in T002 — T001 users must not be able to fetch or view this record.', 'in_progress', 'P1', 'critical', 'high', 'critical', 'network', 'connectivity', 'Corporate WAN', 'USR90001', 'USR90002', 'GRP-T002-NETOPS', 'CI9000001', '["CI9000001"]'::jsonb, NULL, NULL, '[]'::jsonb, '[{"note_id": "WN-INC9001004-01", "author": "USR90002", "author_role": "agent", "is_public": false, "timestamp": "2026-04-09T14:15:00Z", "text": "ISP ticket raised. Circuit engineer dispatched. Failover to 4G backup initiated for critical services."}]'::jsonb, '[]'::jsonb, '2026-04-09T16:00:00Z'::timestamptz, TRUE, '2026-04-09T14:00:00Z'::timestamptz, '2026-04-09T14:15:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T003', 'INC8001001', 'Internal microservices returning 429 rate limit errors', 'TechVentures order-processing service is receiving HTTP 429 responses from the payments and inventory microservices. Issue began after Kong API Gateway config was updated on April 7.', 'in_progress', 'P2', 'high', 'high', 'high', 'network', 'api_gateway', 'API Gateway', 'USR80002', 'USR80001', 'GRP-T003-PLATFORM', 'CI8000001', '["CI8000001", "CI8000002"]'::jsonb, 'PBM8001001', NULL, '[]'::jsonb, '[{"note_id": "WN-INC8001001-01", "author": "USR80001", "author_role": "agent", "is_public": false, "timestamp": "2026-04-08T10:30:00Z", "text": "Confirmed Kong rate-limit plugin applying global 500 req/min cap to all consumers including internal services. Root cause identified in PBM8001001. Whitelist workaround applied to payments and inventory services."}]'::jsonb, '[{"comment_id": "COM-INC8001001-01", "author": "USR80002", "author_role": "customer", "is_public": true, "timestamp": "2026-04-08T10:00:00Z", "text": "Order processing is completely broken \u2014 every order fails with a 429 error. Revenue impact is significant."}]'::jsonb, '2026-04-08T14:00:00Z'::timestamptz, FALSE, '2026-04-08T10:00:00Z'::timestamptz, '2026-04-08T10:30:00Z'::timestamptz, NULL, NULL);
INSERT INTO "incidents" ("tenant_id", "incident_id", "title", "description", "status", "priority", "severity", "impact", "urgency", "category", "subcategory", "service_name", "reported_by", "assigned_to", "assignment_group", "ci_id", "linked_ci_ids", "related_problem", "related_change", "attachments", "work_notes", "comments", "sla_due", "sla_breached", "created_at", "updated_at", "resolved_at", "cross_tenant_references") VALUES ('T003', 'INC8001002', 'Dev Kubernetes cluster pods failing health checks', 'Several pods in the TechVentures development Kubernetes cluster are stuck in CrashLoopBackOff after the API gateway rate limit changes cascaded to the dev environment.', 'open', 'P3', 'medium', 'low', 'medium', 'platform', 'kubernetes', 'Dev Platform', 'USR80002', 'USR80001', 'GRP-T003-PLATFORM', 'CI8000002', '["CI8000002"]'::jsonb, 'PBM8001001', NULL, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '2026-04-10T10:00:00Z'::timestamptz, FALSE, '2026-04-08T11:00:00Z'::timestamptz, '2026-04-08T11:00:00Z'::timestamptz, NULL, NULL);

