  "tenant_id" TEXT,
  "kb_id" TEXT PRIMARY KEY,
  "title" TEXT,
  "summary" TEXT,
  "content" TEXT,
  "category" TEXT,
  "tags" JSONB,
  "state" TEXT,
  "audience" TEXT,
  "created_by" TEXT,
  "created_at" TIMESTAMPTZ,
  "updated_at" TIMESTAMPTZ,
  "views" BIGINT,
  "helpful_votes" BIGINT,
  "related_ci_ids" JSONB,
  "related_incidents" JSONB
);

INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005001', 'Fix VPN disconnects on Wi-Fi handoff', 'Apply VPN client profile v2.3 to fix tunnel drops when roaming between APs.', 'Symptom: VPN tunnel drops when laptop roams between SSIDs or APs.

Cause: Keepalive mismatch between client v2.2 and gateway profile.

Resolution:
1. Confirm client version is v2.2 or earlier.
2. Push v2.3 client profile via Intune.
3. Reboot endpoint.
4. Verify reconnect during AP handoff.', 'network', '["vpn", "wifi", "disconnect", "handoff"]'::jsonb, 'published', 'technician', 'USR00003', '2026-04-01T10:00:00Z'::timestamptz, '2026-04-01T10:00:00Z'::timestamptz, 1820, 412, '["CI0000001", "CI0000002"]'::jsonb, '["INC0001001", "INC0001002", "INC0001019", "INC0001029"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005002', 'Troubleshoot VPN error 809', 'Resolve VPN error 809 by enabling NAT-T on the client and home router.', 'Symptom: VPN client returns error 809 on connect.

Cause: NAT-T (UDP 4500) blocked by home router or local firewall.

Resolution:
1. Confirm client and gateway support NAT-T.
2. On Windows: enable AssumeUDPEncapsulationContextOnSendRule registry key (value 2).
3. On home router: ensure UDP 500 and 4500 are allowed outbound.
4. Restart client and retry connection.', 'network', '["vpn", "error-809", "nat-t"]'::jsonb, 'published', 'end_user', 'USR00003', '2026-04-01T11:00:00Z'::timestamptz, '2026-04-01T11:00:00Z'::timestamptz, 940, 280, '["CI0000001"]'::jsonb, '["INC0001003", "INC0001018"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005003', 'Outlook sync delay checklist', 'Validate transport queue depth and Outlook cache mode when emails arrive late.', 'Symptom: Outlook receives emails with significant delay.

Resolution checklist:
1. Check transport queue depth on Exchange.
2. Confirm Outlook is in cached mode.
3. Validate sync interval settings.
4. Force a manual send/receive.
5. Restart Outlook if backlog persists.', 'email', '["outlook", "sync", "delay"]'::jsonb, 'published', 'all', 'USR00014', '2026-04-01T12:00:00Z'::timestamptz, '2026-04-01T12:00:00Z'::timestamptz, 612, 178, '["CI0000003"]'::jsonb, '["INC0001004"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005004', 'HR portal 500 error first response', 'Capture correlation ID and verify backend health when HR portal returns 500.', 'Symptom: HR portal returns HTTP 500 after SSO redirect.

First response:
1. Capture the X-Correlation-ID header.
2. Verify HR Portal app pool health.
3. Check SAML assertion clock skew between IdP and portal.
4. Retry the SSO token exchange.
5. If correlation ID points at SAML rejection, escalate to GRP-SECOPS.', 'application', '["hr-portal", "500", "sso", "saml"]'::jsonb, 'published', 'technician', 'USR00013', '2026-04-01T13:00:00Z'::timestamptz, '2026-04-01T13:00:00Z'::timestamptz, 524, 161, '["CI0000004"]'::jsonb, '["INC0001006", "INC0001030"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005005', 'Payroll DB deadlock mitigation', 'Run payroll reports against the read-only replica to avoid deadlocks during posting.', 'Symptom: Payroll report generation times out due to deadlocks with posting jobs.

Workaround:
1. Switch report execution to read-only replica.
2. Schedule reports outside of posting windows.
3. Apply CHG0004003 (composite index) for permanent fix.

Validation: report should complete in under 2 minutes.', 'database', '["payroll", "deadlock", "oracle"]'::jsonb, 'published', 'technician', 'USR00004', '2026-04-02T08:00:00Z'::timestamptz, '2026-04-02T08:00:00Z'::timestamptz, 318, 102, '["CI0000005"]'::jsonb, '["INC0001007", "INC0001024"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005006', 'Salesforce sync lag troubleshooting', 'Inspect Kafka consumer lag and restart failed partitions.', 'Symptom: Salesforce records not syncing to ERP for 20+ minutes.

Diagnosis:
1. Check Kafka consumer lag for sf-sync group.
2. Identify failed partitions.
3. Restart consumer process.
4. Verify catch-up rate.', 'integration', '["salesforce", "sync", "kafka"]'::jsonb, 'published', 'technician', 'USR00012', '2026-04-02T09:00:00Z'::timestamptz, '2026-04-02T09:00:00Z'::timestamptz, 245, 71, '["CI0000006"]'::jsonb, '["INC0001008"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005007', 'Wi-Fi floor outage triage', 'Run RF scan and check channel overlap before rebooting APs.', 'Symptom: Multiple users on one floor report Wi-Fi disconnects.

Triage:
1. Run RF scan for affected floor.
2. Identify overlapping channels.
3. Pin channels manually if auto-channel is fighting itself.
4. Validate stability for 30 minutes before closing.', 'network', '["wifi", "ap", "rf"]'::jsonb, 'published', 'technician', 'USR00003', '2026-04-02T10:00:00Z'::timestamptz, '2026-04-02T10:00:00Z'::timestamptz, 401, 118, '["CI0000007"]'::jsonb, '["INC0001009", "INC0001022"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005008', 'MFA reset propagation guide', 'Force user sync after MFA reset to clear stale tokens.', 'Symptom: After password/MFA reset the old token is still required at login.

Resolution:
1. Force user object sync from IdP.
2. Clear stale session tokens.
3. Ask user to re-enroll MFA via portal.', 'security', '["mfa", "sso", "okta"]'::jsonb, 'published', 'all', 'USR00011', '2026-04-02T11:00:00Z'::timestamptz, '2026-04-02T11:00:00Z'::timestamptz, 528, 165, '["CI0000008"]'::jsonb, '["INC0001010", "INC0001021"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005009', 'ITSM portal slowness quick checks', 'Validate API latency and attachment queue backlog when portal is slow.', 'Symptom: Service desk portal pages load slowly.

Quick checks:
1. Check API latency dashboard.
2. Check attachment upload queue depth.
3. Restart upload worker if backlog > 500 items.', 'application', '["itsm", "portal", "performance"]'::jsonb, 'published', 'technician', 'USR00013', '2026-04-02T12:00:00Z'::timestamptz, '2026-04-02T12:00:00Z'::timestamptz, 180, 51, '["CI0000009"]'::jsonb, '["INC0001011", "INC0001023"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005010', 'Monitoring alert delay playbook', 'Verify collector health and ingestion broker lag.', 'Symptom: Monitoring alerts arrive late.

Playbook:
1. Check collector health.
2. Inspect ingestion broker lag.
3. Scale collectors if scrape interval is being missed.', 'platform', '["monitoring", "alerts", "prometheus"]'::jsonb, 'published', 'technician', 'USR00012', '2026-04-02T13:00:00Z'::timestamptz, '2026-04-02T13:00:00Z'::timestamptz, 132, 38, '["CI0000010"]'::jsonb, '["INC0001012", "INC0001027"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T001', 'KB0005011', 'Laptop patch failure remediation', 'Repair installer cache and rerun endpoint patch task.', 'Symptom: Endpoint patch fails with code 1603.

Remediation:
1. Stop Windows Installer service.
2. Clear %windir%\Installer cache for failed package.
3. Restart service.
4. Trigger patch rerun via Intune.', 'endpoint', '["patch", "laptop", "intune"]'::jsonb, 'published', 'technician', 'USR00015', '2026-04-03T08:00:00Z'::timestamptz, '2026-04-03T08:00:00Z'::timestamptz, 94, 28, '["CI0000011"]'::jsonb, '["INC0001013"]'::jsonb);
