INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T002', 'KB9001001', 'SAP ERP peak-hour login workaround', 'Stagger login times to avoid connection pool exhaustion during 09:00-10:00 HKT.', 'Symptom: SAP S/4HANA login times out between 09:00 and 10:00 HKT on weekdays.

Root Cause: Application server connection pool is exhausted at peak login times (240+ concurrent vs 200 pool limit).

Workaround:
- Users with surnames A-M: log in before 09:15 HKT
- Users with surnames N-Z: log in after 09:30 HKT

Permanent fix: CHG9001001 will increase the pool to 500. ETA: 2026-04-12 maintenance window.', 'application', '["sap", "erp", "login", "peak-hours", "connection-pool"]'::jsonb, 'published', 'all', 'USR90002', '2026-04-06T12:00:00Z'::timestamptz, '2026-04-08T09:00:00Z'::timestamptz, 312, 87, '["CI9000002"]'::jsonb, '["INC9001001", "INC9001002"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T002', 'KB9001002', 'GlobalCorp email delivery troubleshooting guide', 'Steps to diagnose and resolve outbound email delivery delays from Exchange Server.', 'Symptom: Outbound emails to external recipients delayed by 10-30 minutes.

Diagnosis steps:
1. Check Exchange message tracking logs for delayed queues.
2. Verify SPF/DKIM/DMARC records are valid.
3. Check recipient MX server reputation and delivery logs.
4. Check smart host relay configuration.

Workaround: Use OWA (web mail) for time-sensitive external messages.

Escalation: If delays persist > 1 hour, raise incident against CI9000003.', 'email', '["email", "exchange", "delivery", "delay", "troubleshooting"]'::jsonb, 'published', 'technician', 'USR90002', '2026-04-10T11:00:00Z'::timestamptz, '2026-04-10T11:00:00Z'::timestamptz, 45, 12, '["CI9000003"]'::jsonb, '["INC9001003"]'::jsonb);
INSERT INTO "kb_knowledge" ("tenant_id", "kb_id", "title", "summary", "content", "category", "tags", "state", "audience", "created_by", "created_at", "updated_at", "views", "helpful_votes", "related_ci_ids", "related_incidents") VALUES ('T003', 'KB8001001', 'Kong API Gateway rate limit configuration for internal services', 'How to configure Kong consumer groups to exempt internal microservices from external rate limits.', 'Problem: Internal microservices receive HTTP 429 errors from Kong API Gateway because they are subject to the same global rate limit policy as external clients.

Solution: Tag internal service consumer accounts with the ''internal-services'' consumer group, then configure the rate-limit plugin to apply only to external consumer groups.

Steps:
1. Log in to Kong Admin API.
2. For each internal service consumer: PATCH /consumers/{consumer_id} with tag ''internal-services''.
3. Update rate-limit plugin to exclude ''internal-services'' tag: set config.consumer_groups = [''external''].
4. Test: call internal service — should receive 200, not 429.
5. Verify external client still receives 429 after rate limit threshold.

Related: PBM8001001, CHG8001001.', 'network', '["kong", "api-gateway", "rate-limit", "microservices", "consumer-groups"]'::jsonb, 'published', 'technician', 'USR80001', '2026-04-09T17:00:00Z'::timestamptz, '2026-04-09T17:00:00Z'::timestamptz, 28, 9, '["CI8000001"]'::jsonb, '["INC8001001", "INC8001002"]'::jsonb);

